text:
{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "participants": [
      "Minjun",
      "Seoyeon",
      "Doyun",
      "Hara"
    ],
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표 시점",
        "decision": "스모크 테스트가 통과하는 경우 금요일 15:00 KST를 공개 릴리스 목표로 한다.",
        "source_certainty": "confirmed"
      },
      {
        "topic": "packageName mismatch 대응 원칙",
        "decision": "packageName mismatch가 발생하면 먼저 package config를 확인하고, 계약 자체가 잘못된 경우에만 스크립트 검토를 진행한다.",
        "source_certainty": "confirmed"
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경",
        "result": "rejected",
        "source_certainty": "confirmed"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "note": "내부 스트레치 골일 뿐 최종 공개 릴리스 결정은 아니다.",
        "source_certainty": "confirmed"
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 단계는 가능하면 목요일까지 검토",
        "reason": "희망 일정만 언급되었고 담당자가 확정되지 않았다.",
        "source_certainty": "confirmed"
      },
      {
        "item": "Hara의 tarball 경로 점검 시점",
        "reason": "Minjun의 스모크 결과 공유 이후 수행하기로 했으나 정확한 기한은 정해지지 않았다.",
        "source_certainty": "confirmed"
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로로 인해 릴리스가 지연될 수 있다.",
        "source_certainty": "confirmed"
      },
      {
        "risk": "README 설치 단계가 오래된 상태라면 릴리스 노트가 사용자에게 오해를 줄 수 있다.",
        "source_certainty": "confirmed"
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?",
        "status": "open",
        "source_certainty": "confirmed"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 골을 언급해야 하는가?",
        "status": "open",
        "source_certainty": "confirmed"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 재실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "failure triage note를 action_items.md에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 후 생성된 tarball 경로를 점검한다.",
      "due": "unspecified",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "unassigned",
      "task": "README 설치 단계를 검토한다.",
      "due": "목요일 가능 시",
      "status": "suggested_without_owner",
      "source_certainty": "partial_confirmed"
    }
  ],
  "followup_note": {
    "check_next": [
      "금요일 10:00 KST 이전 Minjun의 스모크 테스트 재실행 및 결과 공유 여부를 확인한다.",
      "스모크 결과가 나온 뒤 Hara의 tarball 경로 점검 결과를 확인한다.",
      "금요일 12:00 KST 이전 Doyun의 failure triage note 작성 여부를 확인한다.",
      "README 설치 단계 검토의 담당자 지정 여부를 확인한다.",
      "최종 릴리스 승인 권한자와 릴리스 노트의 수요일 스트레치 골 언급 여부를 후속 결정 사항으로 추적한다."
    ],
    "do_not_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요구사항",
      "미지정 담당자",
      "명시되지 않은 추가 기한"
    ]
  },
  "non_invention_rules": [
    "인라인 공개 안전 synthetic fixture에 있는 내용만 사용한다.",
    "확정 결정과 거절된 제안, 내부 스트레치 골, 리스크, 오픈 질문을 분리한다.",
    "고객, 예산, 보안, 장애, 법무, 담당자, 기한 관련 사실은 명시된 범위를 넘어서 추가하지 않는다.",
    "담당자나 기한이 없는 항목은 unassigned 또는 unspecified로 유지한다.",
    "수요일 릴리스는 확정 일정이 아니라 내부 스트레치 골로만 기록한다."
  ]
}
